// ====================================
// NORMALIZADOR DE OUTPUT DEL AGENTE
// Convierte cualquier formato en:
// {
//   subject: "...",
//   mensaje_final: "..."
// }
// ====================================

const rawOutput = $input.first().json.output || "";

// ====================================
// LIMPIADOR DE OUTPUT
// ====================================

function limpiarOutputAgente(output) {
  if (!output) return "";

  let limpio = output.trim();

  // Quitar bloques ```json ``` o ``` ```
  limpio = limpio.replace(/^```json/i, "");
  limpio = limpio.replace(/^```/, "");
  limpio = limpio.replace(/```$/, "");

  // Quitar "json\n" o "json"
  limpio = limpio.replace(/^json\s*/i, "");

  // Si viene como string escapado
  if (limpio.startsWith('"') && limpio.endsWith('"')) {
    try {
      limpio = JSON.parse(limpio);
    } catch (_) {
      limpio = limpio.slice(1, -1);
    }
  }

  return limpio.trim();
}

// ====================================
// PROCESAR OUTPUT DEL AGENTE
// ====================================

let mensajeFinal = "";
let subjectFinal = "";

try {
  const limpio = limpiarOutputAgente(rawOutput);

  const data = JSON.parse(limpio);

  mensajeFinal = data.mensaje_final || "";
  subjectFinal = data.subject || "";

} catch (err) {
  // Fallback ultra seguro
  mensajeFinal = rawOutput;
  subjectFinal = "";
}

// ====================================
// FALLBACK DE SUBJECT (SI EL AGENTE FALLA)
// ====================================

if (!subjectFinal) {
  const subjectsFallback = [
    "Consulta rápida",
    "Pregunta breve",
    "Una duda",
    "Sobre tu empresa",
    "Contacto inicial"
  ];

  subjectFinal =
    subjectsFallback[
      Math.floor(Math.random() * subjectsFallback.length)
    ];
}

// ====================================
// OUTPUT FINAL PARA N8N
// ====================================

return [
  {
    json: {
      subject: subjectFinal,
      mensaje_final: mensajeFinal,
      procesado_correctamente: true,
      timestamp: new Date().toISOString()
    }
  }
];

// Forzar zona horaria a America/Mexico_City
const now = new Date(
  new Date().toLocaleString("en-US", { timeZone: "America/Mexico_City" })
);

// Obtener datos
const day = now.getDay();      // 0 = domingo, 1 = lunes ... 5 = viernes
const hour = now.getHours();   // 0–23
const minute = now.getMinutes(); // 0–59

// Validaciones
const isBusinessDay = day >= 1 && day <= 5;

// Horario permitido:
// 09:00 → 16:30
// 17:00 sí
// 17:30 NO
const isBusinessHour =
  (hour >= 9 && hour < 17) ||
  (hour === 17 && minute === 0);

// Solo cada 30 minutos exactos
const isHalfHour = minute === 0 || minute === 30;

if (isBusinessDay && isBusinessHour && isHalfHour) {
  return [{
    json: {
      ok: true,
      message: "Dentro del horario permitido (cada 30 minutos)",
      fecha_mexico: now.toString(),
      hour,
      minute
    }
  }];
}

// Fuera del horario → detener flujo devolviendo 0 items
return [];
